diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 5eebfdb774d2..eaf2437e8947 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3166,12 +3166,18 @@ static bool impliesPoisonOrCond(const Value *ValAssumedPoison, const Value *V,
         match(ICmp->getOperand(1), m_APIntForbidPoison(RHSC1)) &&
         match(V, m_ICmp(Pred, m_Specific(LHS), m_APIntAllowPoison(RHSC2)))) {
       unsigned BitWidth = RHSC1->getBitWidth();
-      ConstantRange CRX =
-          RHSC1->isNonNegative()
-              ? ConstantRange(APInt::getSignedMinValue(BitWidth),
-                              APInt::getZero(BitWidth))
-              : ConstantRange(APInt::getZero(BitWidth),
-                              APInt::getSignedMinValue(BitWidth));
+      ConstantRange CRX;
+      if (RHSC1->isNonNegative()) {
+        CRX = ConstantRange(APInt::getSignedMinValue(BitWidth),
+                            APInt::getZero(BitWidth));
+      } else if (RHSC1->isNegative()) {
+        CRX = ConstantRange(APInt::getZero(BitWidth),
+                            APInt::getSignedMinValue(BitWidth));
+      } else {
+        // If RHSC1 is not strictly non-negative or negative, we cannot make
+        // any assumptions about the poison safety of ValAssumedPoison.
+        return false;
+      }
       return CRX.icmp(Expected ? Pred : ICmpInst::getInverseCmpPredicate(Pred),
                       *RHSC2);
     }
